const e={configEditor:{intro:{t:0,b:{t:2,i:[{t:3}],s:"Lies die aktive Konfiguration deines Druckers direkt aus Moonraker — jede Datei, aufgeteilt in Sektionen und Parameter, mit Hinweisen auf strukturelle Probleme. Vorerst nur lesend; geführtes Bearbeiten folgt als Nächstes."}},help:{guide:{t:0,b:{t:2,i:[{t:3}],s:"Hilfe"}},guideTitle:{t:0,b:{t:2,i:[{t:3}],s:"Über den Config Editor"}},close:{t:0,b:{t:2,i:[{t:3}],s:"Schließen"}},howToRead:{t:0,b:{t:2,i:[{t:3}],s:"So geht's"}},steps:[{t:0,b:{t:2,i:[{t:3}],s:"Wähle eine Konfigurationsdatei aus dem Dropdown — printer.cfg ist standardmäßig ausgewählt."}},{t:0,b:{t:2,i:[{t:3}],s:"Durchsuche die Sektionen; klicke auf eine, um ihre Parameter auszuklappen."}},{t:0,b:{t:2,i:[{t:3}],s:"Prüfe das Validierungs-Banner auf strukturelle Probleme wie eine doppelte Sektion."}},{t:0,b:{t:2,i:[{t:3}],s:"Wechsle zu Roh, um den exakten Dateitext zu lesen."}}],topics:{sections:{title:{t:0,b:{t:2,i:[{t:3}],s:"Sektionen & Parameter"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Eine Klipper-Konfiguration ist eine Liste von [section]-Blöcken, die jeweils key: value-Parameter enthalten. Dieses Widget zerlegt jede Sektion — auch solche mit einem Namen wie [tmc2209 stepper_x] — und listet ihre Parameter mit ihrem Wert und etwaigen Inline-Kommentaren auf. Mehrzeilige Werte (etwa das gcode: eines Makros) bleiben unverändert erhalten."}}},includes:{title:{t:0,b:{t:2,i:[{t:3}],s:"Eingebundene Dateien"}},body:{t:0,b:{t:2,i:[{t:3}],s:"printer.cfg bindet oft weitere Dateien per [include other.cfg] ein (oder einen Glob wie [include configs/*.cfg]). Jedes Include wird als eigener Eintrag angezeigt; wähle die eingebundene Datei aus dem Dropdown, um zu prüfen, was sie definiert."}}},validation:{title:{t:0,b:{t:2,i:[{t:3}],s:"Validierung"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Nach dem Parsen wird die Konfiguration auf strukturelle Probleme geprüft, die unabhängig vom Sektionstyp falsch sind — ein doppelter Sektions-Header, ein leerer Sektionsname oder ein Parameter, der außerhalb jeder Sektion steht. Diese erscheinen im Validierungs-Banner; sie verändern deine Datei nicht."}}},saveConfig:{title:{t:0,b:{t:2,i:[{t:3}],s:"Der SAVE_CONFIG-Block"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Klipper hängt am Ende von printer.cfg (nach der #*#-Markierung) einen automatisch erzeugten Block an, wenn du SAVE_CONFIG ausführst — Kalibrierungsergebnisse wie PID- und Z-Offsets. Er wird angezeigt, aber als automatisch gespeichert gekennzeichnet und von der Zählung der bearbeitbaren Sektionen ausgeschlossen, weil du ihn nicht von Hand bearbeiten solltest."}}},readonly:{title:{t:0,b:{t:2,i:[{t:3}],s:"Nur lesend (vorerst)"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Diese erste Version liest die Konfiguration nur und zeigt sie an — es wird nichts auf den Drucker geschrieben. Geführtes, mit Bestätigung abgesichertes Bearbeiten (mit automatischem Backup vor jedem Speichern und anschließendem Neustart) kommt in einem späteren Update."}}},glossary:{title:{t:0,b:{t:2,i:[{t:3}],s:"Glossar"}},body:{t:0,b:{static:"",t:2,i:[]}}}},glossary:{section:{term:{t:0,b:{t:2,i:[{t:3}],s:"Sektion"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Ein [header]-Block, der zusammengehörige Einstellungen gruppiert, z. B. [stepper_x] oder [extruder]."}}},parameter:{term:{t:0,b:{t:2,i:[{t:3}],s:"Parameter"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Eine key: value- (oder key = value-) Zeile innerhalb einer Sektion, optional mit einem nachgestellten #-Kommentar."}}},include:{term:{t:0,b:{t:2,i:[{t:3}],s:"[include]"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Eine Direktive, die eine weitere Konfigurationsdatei in printer.cfg einbindet, sodass Einstellungen auf mehrere Dateien aufgeteilt werden können."}}},saveConfig:{term:{t:0,b:{t:2,i:[{t:3}],s:"SAVE_CONFIG"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Der automatisch erzeugte Block (nach #*#), in dem Klipper Kalibrierungsergebnisse speichert — nicht von Hand bearbeiten."}}}}},file:{label:{t:0,b:{t:2,i:[{t:3}],s:"Konfigurationsdatei"}},placeholder:{t:0,b:{t:2,i:[{t:3}],s:"Datei auswählen…"}},refresh:{t:0,b:{t:2,i:[{t:3}],s:"Aktualisieren"}},loadingList:{t:0,b:{t:2,i:[{t:3}],s:"Dateien werden geladen…"}},emptyList:{t:0,b:{t:2,i:[{t:3}],s:"Keine Konfigurationsdateien auf dem Drucker gefunden."}}},summary:{sections:{t:0,b:{t:2,i:[{t:4,k:"count"},{t:3,v:" Sektionen"}]}},params:{t:0,b:{t:2,i:[{t:4,k:"count"},{t:3,v:" Parameter"}]}},size:{t:0,b:{t:2,i:[{t:4,k:"kb"},{t:3,v:" KB"}]}}},validation:{title:{t:0,b:{t:2,i:[{t:3}],s:"Validierung"}},clean:{t:0,b:{t:2,i:[{t:3}],s:"Keine strukturellen Probleme gefunden."}},error:{t:0,b:{t:2,i:[{t:3}],s:"Fehler"}},warning:{t:0,b:{t:2,i:[{t:3}],s:"Warnung"}}},view:{structured:{t:0,b:{t:2,i:[{t:3}],s:"Strukturiert"}},raw:{t:0,b:{t:2,i:[{t:3}],s:"Roh"}},expandAll:{t:0,b:{t:2,i:[{t:3}],s:"Alle ausklappen"}},collapseAll:{t:0,b:{t:2,i:[{t:3}],s:"Alle einklappen"}}},section:{saveBadge:{t:0,b:{t:2,i:[{t:3}],s:"automatisch gespeichert"}},noParams:{t:0,b:{t:2,i:[{t:3}],s:"(keine Parameter)"}},paramsCount:{t:0,b:{t:2,i:[{t:4,k:"count"},{t:3,v:" Parameter"}]}},paramHead:{t:0,b:{t:2,i:[{t:3}],s:"Parameter"}},valueHead:{t:0,b:{t:2,i:[{t:3}],s:"Wert"}}},states:{loading:{t:0,b:{t:2,i:[{t:3}],s:"Konfiguration wird gelesen…"}},error:{t:0,b:{t:2,i:[{t:3}],s:"Die Konfiguration konnte nicht vom Drucker gelesen werden."}},retry:{t:0,b:{t:2,i:[{t:3}],s:"Erneut versuchen"}}}}};export{e as default};
